from collections import deque


class Solution:
    def minOperations(self, n):
        if n == 0:
            return 0
        limit = 1
        while limit < 2 * n + 2:
            limit *= 2
        powers = []
        p = 1
        while p <= limit:
            powers.append(p)
            p *= 2
        visited = {n}
        q = deque([(n, 0)])
        while q:
            cur, d = q.popleft()
            if cur == 0:
                return d
            for p in powers:
                for nxt in (cur - p, cur + p):
                    if -limit <= nxt <= limit and nxt not in visited:
                        visited.add(nxt)
                        q.append((nxt, d + 1))
        return -1

